mapper.select:
select base_dt, bf_bf_biz_dt, bf_biz_dt, biz_dt, nxt_biz_dt, nxt_nxt_biz_dt, hldy_yn, inst_cd
  from cotdl.tbl_piibizday 
  where base_dt= #{base_dt, jdbcType=VARCHAR}

 
		 
		select 
			base_dt, bf_bf_biz_dt, bf_biz_dt, biz_dt, nxt_biz_dt, nxt_nxt_biz_dt, hldy_yn, inst_cd
		from ( 
				select 
					 ROWNUM rn, base_dt, bf_bf_biz_dt, bf_biz_dt, biz_dt, nxt_biz_dt, nxt_nxt_biz_dt, hldy_yn, inst_cd
				from (
						select base_dt, bf_bf_biz_dt, bf_biz_dt, biz_dt, nxt_biz_dt, nxt_nxt_biz_dt, hldy_yn, inst_cd
						  from cotdl.tbl_piibizday 
						 order by base_dt
					 ) a 
				where
		
	    
		 
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by base_dt 
			  ) f
		where rn > (#{pagenum} -1) * #{amount} 
		order by base_dt


	select concat('str_to_date(''',min(deadline),''',%Y%m%d)')
	from (select base_dt as deadline
		  from (
				   select row_number() over(order by base_dt desc) as rn, base_dt
				   from cotdl.tbl_piibizday
				   where hldy_yn='N' and base_dt < #{basedate, jdbcType=VARCHAR}
			   ) a
		  where  rn = #{cnt}
		  order by rn desc
		 ) f
	group by deadline


	select concat('str_to_date(''',max(deadline),''',%Y%m%d)')
	from (select base_dt as deadline
		  from (
				   select  row_number() over(order by base_dt) as rn, base_dt
				   from cotdl.tbl_piibizday
				   where hldy_yn='N' and base_dt > #{basedate, jdbcType=VARCHAR}
			   ) a
		  where  rn = #{cnt}
		  order by rn
		 ) f
	group by deadline
